browser_js({"code":"(() => {
  const svgs = document.querySelectorAll('svg[aria-label], [data-testid]');
  const labels = new Set();
  const testIds = new Set();
  svgs.forEach(s => {
    const label = s.getAttribute('aria-label');
    const testId = s.getAttribute('data-testid');
    if (label) labels.add(label);
    if (testId) testIds.add(testId);
  });

  const navLinks = new Set();
  document.querySelectorAll('a[href]').forEach(l => {
    const href = l.getAttribute('href');
    if (href && href.startsWith('/') && href.length < 30) navLinks.add(href);
  });

  const inputs = [];
  document.querySelectorAll('textarea, input[type="text"], div[role="textbox"], div[contenteditable]').forEach(i => {
    inputs.push({ tag: i.tagName, placeholder: i.placeholder || i.getAttribute('aria-label') || i.getAttribute('data-testid') });
  });

  return {
    title: document.title,
    url: window.location.href,
    ariaLabels: [...labels].slice(0, 30),
    testIds: [...testIds].slice(0, 30),
    navLinks: [...navLinks].slice(0, 15),
    inputs
  };
})()","tabId":"38D17DD0A099A9CF6137F60932C98F15"})

browser_js({"code":"(() => {
  return new Promise(resolve => {
    setTimeout(() => {
      // Extract feed posts
      const tweets = document.querySelectorAll('article[data-testid="tweet"]');
      const posts = [];
      tweets.forEach((t, i) => {
        if (i >= 5) return;
        const username = t.querySelector('div[data-testid="User-Name"]')?.textContent?.trim();
        const text = t.querySelector('div[data-testid="tweetText"]')?.textContent?.trim();
        const hasLike = !!t.querySelector('[data-testid="like"]');
        const hasReply = !!t.querySelector('[data-testid="reply"]');
        const hasRetweet = !!t.querySelector('[data-testid="retweet"]');
        const hasBookmark = !!t.querySelector('[data-testid="bookmark"]');
        posts.push({ username: username?.substring(0, 50), text: text?.substring(0, 80), hasLike, hasReply, hasRetweet, hasBookmark });
      });

      // Get all testids for post actions
      const firstTweet = tweets[0];
      const actionTestIds = [];
      if (firstTweet) {
        firstTweet.querySelectorAll('[data-testid]').forEach(el => {
          actionTestIds.push(el.getAttribute('data-testid'));
        });
      }

      resolve({ tweetCount: tweets.length, posts, actionTestIds });
    }, 2000);
  });
})()","tabId":"38D17DD0A099A9CF6137F60932C98F15"})

