browser_js({"code":"(() => {
  // Check for retweet dropdown menu more broadly
  const allItems = document.querySelectorAll('[role="menuitem"], [role="menu"] *, div[id="layers"] *');
  const texts = new Set();
  allItems.forEach(el => {
    const t = el.textContent?.trim();
    if (t && t.length > 1 && t.length < 30) texts.add(t);
  });

  // Also look for data-testid containing retweet
  const retweetEls = document.querySelectorAll('[data-testid*="retweet"], [data-testid*="Retweet"]');
  const testIds = [];
  retweetEls.forEach(el => testIds.push(el.getAttribute('data-testid')));

  return { menuTexts: [...texts].slice(0, 15), retweetTestIds: testIds };
})()","tabId":"38D17DD0A099A9CF6137F60932C98F15"})

browser_js({"code":"(() => {
  // Click the retweet button on the first tweet more precisely
  const tweet = document.querySelector('article[data-testid="tweet"]');
  const retweetBtn = tweet?.querySelector('[data-testid="retweet"]');
  if (!retweetBtn) return 'No retweet button';

  const rect = retweetBtn.getBoundingClientRect();
  return { x: rect.x + rect.width/2, y: rect.y + rect.height/2, width: rect.width, height: rect.height };
})()","tabId":"38D17DD0A099A9CF6137F60932C98F15"})

browser_js({"code":"(() => {
  return new Promise(resolve => {
    setTimeout(() => {
      // Look in the layers div for the dropdown
      const layers = document.querySelector('div[id="layers"]');
      if (!layers) return resolve({ layers: false });

      const items = layers.querySelectorAll('[role="menuitem"]');
      const menuItems = [];
      items.forEach(m => menuItems.push({ testId: m.getAttribute('data-testid'), text: m.textContent?.trim() }));

      // Also check broader
      const allClickable = layers.querySelectorAll('div[role="button"], button, a');
      const clickTexts = [];
      allClickable.forEach(c => {
        const t = c.textContent?.trim();
        if (t && t.length < 30) clickTexts.push(t);
      });

      resolve({ layers: true, menuItems, clickTexts });
    }, 1000);
  });
})()","tabId":"38D17DD0A099A9CF6137F60932C98F15"})

browser_js({"code":"(() => {
  // Check for any overlay/modal blocking interaction
  const layers = document.querySelector('div[id="layers"]');
  const children = [];
  if (layers) {
    layers.children[0]?.querySelectorAll('div, span, input').forEach(el => {
      const t = el.textContent?.trim();
      const tag = el.tagName;
      const type = el.type;
      const ph = el.placeholder;
      if ((t && t.length > 2 && t.length < 50) || ph) {
        children.push({ tag, text: t?.substring(0, 40), type, placeholder: ph });
      }
    });
  }
  return { layerChildren: children.slice(0, 15) };
})()","tabId":"38D17DD0A099A9CF6137F60932C98F15"})
